import { parseSetCookie } from './set-cookie.mjs';

export class CookieJar {
  #entries = [];

  store(value, origin, now = 0) {
    const url = new URL(origin);
    const parsed = parseSetCookie(value);
    const domain = parsed.domain ?? url.hostname.toLowerCase();
    if (parsed.domain !== null && !url.hostname.toLowerCase().endsWith(domain)) {
      throw new TypeError('cookie domain does not cover the origin');
    }
    const expiresAt = parsed.maxAge === null ? null : now + parsed.maxAge * 1000;
    this.#entries = this.#entries.filter((entry) => !(
      entry.name === parsed.name && entry.domain === domain && entry.path === parsed.path
    ));
    if (expiresAt !== null && expiresAt <= now) return;
    this.#entries.push({ ...parsed, domain, expiresAt });
  }

  cookiesFor(target, now = 0) {
    const url = new URL(target);
    const host = url.hostname.toLowerCase();
    this.#entries = this.#entries.filter(
      (entry) => entry.expiresAt === null || entry.expiresAt > now
    );
    return this.#entries
      .filter((entry) => host.endsWith(entry.domain))
      .filter((entry) => url.pathname.startsWith(entry.path))
      .filter((entry) => !entry.secure || url.protocol === 'https:')
      .sort((left, right) => right.path.length - left.path.length)
      .map(({ name, value }) => ({ name, value }));
  }
}

