import test from 'node:test';
import assert from 'node:assert/strict';

import { CookieJar } from '../src/cookie-jar.mjs';
import { formatCookieHeader } from '../src/cookie-header.mjs';
import { parseSetCookie } from '../src/set-cookie.mjs';

test('ordinary host-only cookies retain their public shape', () => {
  assert.deepEqual(parseSetCookie('sid=abc; Path=/app; Secure'), {
    name: 'sid', value: 'abc', domain: null, path: '/app', secure: true, maxAge: null
  });
  const jar = new CookieJar();
  jar.store('sid=abc; Path=/app; Secure', 'https://api.example.test/app/login');
  assert.equal(
    formatCookieHeader(jar.cookiesFor('https://api.example.test/app/items')),
    'sid=abc'
  );
  assert.equal(formatCookieHeader(jar.cookiesFor('http://api.example.test/app/items')), '');
});
